//! Spec-compliance tests: Table Border Resolution
//!
//! These tests verify correct OOXML behavior for table border resolution
//! per ISO 29500-1 and MS-OI29500.
//!
//! Fixture DOCX files are generated by:
//! `testdata/spec-compliance/table-border-bugs/create_fixtures.py`
//!
//! Constraints covered:
//! 1. Table->cell border fallback (SS17.4.66)
//! 2. insideV/insideH edge selection (SS17.4.66 + SS17.4.38)
//! 3. tblLook default bitmask (MS-OI29500 SS17.4.55)
//! 4. Adjacent cell border conflict resolution (SS17.4.66 rule 3)

use stemma::{BlockNode, BorderStyle, CanonDoc};

use crate::common;

const FIXTURES: &str = "testdata/spec-compliance/table-border-bugs";

// -- helpers ------------------------------------------------------------------

fn first_table(doc: &CanonDoc) -> &stemma::TableNode {
    doc.blocks
        .iter()
        .find_map(|b| match &b.block {
            BlockNode::Table(t) => Some(t),
            _ => None,
        })
        .expect("document should contain at least one table")
}

// =============================================================================
// 1. Table->cell border fallback
// ISO 29500-1 SS17.4.66: Cells without tcBorders inherit from tblBorders
// =============================================================================

/// SS17.4.66: When a cell has no tcBorders element, the table-level
/// tblBorders should serve as the effective borders for that cell.
/// A 2x2 table with red single sz=12 tblBorders on all edges and
/// NO tcBorders on any cell should produce cells with inherited borders.
#[test]
fn bug1_cells_without_tcborders_inherit_table_borders() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "border-fallback");
    let table = first_table(&doc);

    // Precondition: table-level borders exist.
    let tbl_borders = table
        .formatting
        .borders
        .as_ref()
        .expect("table should have tblBorders");
    assert!(tbl_borders.top.is_some(), "table should have top border");
    assert!(tbl_borders.left.is_some(), "table should have left border");
    assert!(
        tbl_borders.inside_h.is_some(),
        "table should have insideH border"
    );
    assert!(
        tbl_borders.inside_v.is_some(),
        "table should have insideV border"
    );

    // Cell (0,0) — top-left corner.
    // Per SS17.4.66: top=table.top, left=table.left,
    //   bottom=table.insideH, right=table.insideV
    let borders_00 = table.rows[0].cells[0].formatting.borders.as_ref().expect(
        "cell (0,0) should have borders inherited from tblBorders — \
                 SS17.4.66 says table borders serve as defaults when tcBorders is absent",
    );

    assert!(
        borders_00.top.is_some(),
        "cell (0,0) top should inherit from tblBorders.top"
    );
    assert!(
        borders_00.left.is_some(),
        "cell (0,0) left should inherit from tblBorders.left"
    );
    assert!(
        borders_00.bottom.is_some(),
        "cell (0,0) bottom should inherit from tblBorders.insideH"
    );
    assert!(
        borders_00.right.is_some(),
        "cell (0,0) right should inherit from tblBorders.insideV"
    );

    // Verify color matches table-level (all borders are red "FF0000").
    assert_eq!(
        borders_00.top.as_ref().unwrap().color.as_deref(),
        Some("FF0000"),
        "cell (0,0) top border color should be FF0000 (from tblBorders)"
    );
    assert_eq!(
        borders_00.top.as_ref().unwrap().size,
        Some(12),
        "cell (0,0) top border size should be 12 (from tblBorders)"
    );
}

/// SS17.4.66: All four cells in a 2x2 table without tcBorders should
/// have borders populated from tblBorders.
#[test]
fn bug1_all_cells_get_borders_from_table() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "border-fallback");
    let table = first_table(&doc);

    for row_idx in 0..2 {
        for cell_idx in 0..2 {
            let cell = &table.rows[row_idx].cells[cell_idx];
            let borders = cell.formatting.borders.as_ref();
            assert!(
                borders.is_some(),
                "cell ({row_idx},{cell_idx}) should have borders — \
                 SS17.4.66 requires fallback to tblBorders"
            );
            let b = borders.unwrap();
            assert!(
                b.top.is_some(),
                "cell ({row_idx},{cell_idx}) should have top border"
            );
            assert!(
                b.bottom.is_some(),
                "cell ({row_idx},{cell_idx}) should have bottom border"
            );
            assert!(
                b.left.is_some(),
                "cell ({row_idx},{cell_idx}) should have left border"
            );
            assert!(
                b.right.is_some(),
                "cell ({row_idx},{cell_idx}) should have right border"
            );
        }
    }
}

// =============================================================================
// 2. insideV/insideH edge selection
// ISO 29500-1 SS17.4.66 + SS17.4.38: Interior cells use insideV/insideH,
// not the table's outer left/right/top/bottom borders.
// =============================================================================

/// SS17.4.66: Interior cell (0,1) in a 2x3 table should get its left border
/// from insideV (green single sz=4), NOT from the table's outer left border
/// (blue double sz=12).
#[test]
fn bug2_interior_cell_left_uses_inside_v() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "inside-v-distinct");
    let table = first_table(&doc);

    let tbl_borders = table
        .formatting
        .borders
        .as_ref()
        .expect("table should have borders");

    // Verify table-level border setup.
    let outer_left = tbl_borders.left.as_ref().unwrap();
    let inside_v = tbl_borders.inside_v.as_ref().unwrap();
    assert_eq!(
        outer_left.color.as_deref(),
        Some("0000FF"),
        "table outer left should be blue"
    );
    assert_eq!(
        inside_v.color.as_deref(),
        Some("00FF00"),
        "table insideV should be green"
    );

    // Cell (0,1) is the middle column. Its left border should come from
    // insideV (green), not the table's left (blue).
    let cell_01_borders = table.rows[0].cells[1]
        .formatting
        .borders
        .as_ref()
        .expect("cell (0,1) should have borders");

    let left = cell_01_borders
        .left
        .as_ref()
        .expect("cell (0,1) should have a left border");
    assert_eq!(
        left.color.as_deref(),
        Some("00FF00"),
        "cell (0,1) left border should be green (insideV), not blue (outer left) — \
         SS17.4.66: interior vertical edges use insideV"
    );
    assert_eq!(
        left.style,
        BorderStyle::Single,
        "cell (0,1) left border style should be Single (from insideV)"
    );
    assert_eq!(
        left.size,
        Some(4),
        "cell (0,1) left border size should be 4 (from insideV)"
    );
}

/// SS17.4.66: Interior cell (0,1) right border should also come from insideV
/// (green), not the table's outer right (blue).
#[test]
fn bug2_interior_cell_right_uses_inside_v() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "inside-v-distinct");
    let table = first_table(&doc);

    let inside_v = table
        .formatting
        .borders
        .as_ref()
        .unwrap()
        .inside_v
        .as_ref()
        .unwrap();

    let cell_01_borders = table.rows[0].cells[1]
        .formatting
        .borders
        .as_ref()
        .expect("cell (0,1) should have borders");

    let right = cell_01_borders
        .right
        .as_ref()
        .expect("cell (0,1) should have a right border");
    assert_eq!(
        right.color.as_deref(),
        inside_v.color.as_deref(),
        "cell (0,1) right border should match insideV color — \
         SS17.4.66: non-rightmost cell uses insideV for right border"
    );
}

/// SS17.4.66: Cell (0,1) bottom border should come from insideH (red dashed
/// sz=8), not the table's outer bottom (blue double sz=12).
#[test]
fn bug2_interior_cell_bottom_uses_inside_h() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "inside-v-distinct");
    let table = first_table(&doc);

    let tbl_borders = table.formatting.borders.as_ref().unwrap();
    let inside_h = tbl_borders.inside_h.as_ref().unwrap();
    assert_eq!(
        inside_h.color.as_deref(),
        Some("FF0000"),
        "insideH should be red"
    );
    assert_eq!(
        inside_h.style,
        BorderStyle::Dashed,
        "insideH should be dashed"
    );

    // Cell (0,1) is not bottom row, so bottom border should come from insideH.
    let cell_01_borders = table.rows[0].cells[1]
        .formatting
        .borders
        .as_ref()
        .expect("cell (0,1) should have borders");

    let bottom = cell_01_borders
        .bottom
        .as_ref()
        .expect("cell (0,1) should have a bottom border");
    assert_eq!(
        bottom.color.as_deref(),
        Some("FF0000"),
        "cell (0,1) bottom border should be red (insideH), not blue (outer bottom) — \
         SS17.4.66: non-bottom-row cells use insideH for bottom border"
    );
    assert_eq!(
        bottom.style,
        BorderStyle::Dashed,
        "cell (0,1) bottom border should be dashed (from insideH)"
    );
}

/// SS17.4.66: Edge cell (0,0) should use the table's outer left border,
/// NOT insideV, because it is the leftmost cell.
#[test]
fn bug2_edge_cell_uses_outer_border() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "inside-v-distinct");
    let table = first_table(&doc);

    let tbl_borders = table.formatting.borders.as_ref().unwrap();
    let outer_left = tbl_borders.left.as_ref().unwrap();

    let cell_00_borders = table.rows[0].cells[0]
        .formatting
        .borders
        .as_ref()
        .expect("cell (0,0) should have borders");

    let left = cell_00_borders
        .left
        .as_ref()
        .expect("cell (0,0) should have a left border");
    assert_eq!(
        left.color.as_deref(),
        outer_left.color.as_deref(),
        "cell (0,0) left border should be blue (outer left) — \
         SS17.4.66: leftmost cell uses table outer left border"
    );
    assert_eq!(
        left.style,
        BorderStyle::Double,
        "cell (0,0) left border should be Double (from table outer left)"
    );
}

// =============================================================================
// 3. tblLook default bitmask
// MS-OI29500 SS17.4.55(a): When tblLook is omitted, default is 0x04A0.
// 0x04A0 = firstRow(0x0020) | firstColumn(0x0080) | noVBand(0x0400).
// firstColumn=true means firstCol conditional should apply.
// noHBand=false means horizontal banding should apply.
// =============================================================================

/// MS-OI29500 SS17.4.55(a): TblLook::default() must match bitmask 0x04A0.
/// This is a unit-level check — no fixture needed.
#[test]
fn bug3_tbllook_default_matches_0x04a0() {
    let default = stemma::TblLook::default();

    // 0x04A0 = firstRow | firstCol | noVBand (all others false)
    assert!(
        default.first_row,
        "MS default 0x04A0: firstRow should be true (bit 0x0020)"
    );
    assert!(
        default.first_column,
        "MS default 0x04A0: firstColumn should be true (bit 0x0080)"
    );
    assert!(
        default.no_v_band,
        "MS default 0x04A0: noVBand should be true (bit 0x0400)"
    );
    assert!(
        !default.last_row,
        "MS default 0x04A0: lastRow should be false"
    );
    assert!(
        !default.last_column,
        "MS default 0x04A0: lastCol should be false"
    );
    assert!(
        !default.no_h_band,
        "MS default 0x04A0: noHBand should be false (bit 0x0200 NOT set)"
    );
}

/// MS-OI29500 SS17.4.55(a): When tblLook is omitted, firstCol conditional
/// formatting should apply because the default has firstColumn=true.
///
/// Table uses a style with firstCol conditional (yellow shading FFFF00).
/// With no tblLook element, the default 0x04A0 enables firstColumn.
/// Column 0 cells should get yellow shading from firstCol conditional.
#[test]
fn bug3_omitted_tbllook_applies_first_col_conditional() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "tbllook-default-omitted");
    let table = first_table(&doc);

    // Row 1 (not firstRow, so firstRow conditional shouldn't interfere)
    // Cell (1,0) is in firstCol — should have yellow shading from firstCol conditional.
    let cell_10_shading = table.rows[1].cells[0].formatting.shading.as_ref();
    assert!(
        cell_10_shading.is_some(),
        "cell (1,0) should have shading from firstCol conditional — \
         default tblLook (0x04A0) has firstColumn=true, so firstCol conditional \
         should apply to column 0"
    );
    if let Some(s) = cell_10_shading {
        assert_eq!(
            s.fill.as_deref(),
            Some("FFFF00"),
            "cell (1,0) should have yellow shading (FFFF00) from firstCol conditional"
        );
    }
}

/// MS-OI29500 SS17.4.55(a): Default tblLook has noHBand=false, so horizontal
/// banding should apply. Data rows (after firstRow) should get band shading.
///
/// Row 2 is a data row (data_row_idx=1 since firstRow is enabled by default).
/// Cell (2,1) is NOT in firstCol, so should get band shading if noHBand=false.
#[test]
fn bug3_omitted_tbllook_enables_horizontal_banding() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "tbllook-default-omitted");
    let table = first_table(&doc);

    // Cell (1,1) — row 1, col 1: not firstRow, not firstCol.
    // With default tblLook (0x04A0):
    //   firstRow=true -> row 0 is firstRow
    //   noHBand=false -> banding applies to data rows
    //   data_row_idx for row 1 = 0 (first data row) -> band1Horz (gray D9D9D9)
    let cell_11_shading = table.rows[1].cells[1].formatting.shading.as_ref();
    assert!(
        cell_11_shading.is_some(),
        "cell (1,1) should have band1Horz shading — \
         default tblLook has noHBand=false, so banding should apply"
    );
    if let Some(s) = cell_11_shading {
        assert_eq!(
            s.fill.as_deref(),
            Some("D9D9D9"),
            "cell (1,1) should have gray shading (D9D9D9) from band1Horz"
        );
    }
}

// =============================================================================
// 4. Adjacent cell border conflict resolution
// ISO 29500-1 SS17.4.66 rule 3: When adjacent cells have conflicting
// borders, the border with higher weight (style_rank * size) wins.
// =============================================================================

/// Verifies SS17.4.66 rule 3 conflict resolution at the shared edge between
/// cell (0,0) and cell (0,1). Cell (0,0) has right border single sz=24 red
/// (weight=24) and cell (0,1) has left border single sz=4 blue (weight=4).
/// The heavier border (red) wins and appears on both cells' shared edge.
#[test]
fn bug4_adjacent_cell_shared_edge_uses_heavier_border() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "adjacent-conflict");
    let table = first_table(&doc);

    // Cell (0,0) right border: single sz=24 red (weight = 1 * 24 = 24)
    let _cell_00_right = table.rows[0].cells[0]
        .formatting
        .borders
        .as_ref()
        .and_then(|b| b.right.as_ref())
        .expect("cell (0,0) should have a right border");

    // Cell (0,1) left border: single sz=4 blue (weight = 1 * 4 = 4)
    let cell_01_left = table.rows[0].cells[1]
        .formatting
        .borders
        .as_ref()
        .and_then(|b| b.left.as_ref())
        .expect("cell (0,1) should have a left border");

    // Per SS17.4.66 rule 3: the heavier border wins the shared edge.
    // Red (weight=24) wins over blue (weight=4).
    // After resolution, BOTH cells' shared edge should display the red border.
    assert_eq!(
        cell_01_left.color.as_deref(),
        Some("FF0000"),
        "cell (0,1) left border should be red (winner from conflict resolution) — \
         SS17.4.66 rule 3: cell (0,0) right (weight=24) beats cell (0,1) left (weight=4)"
    );
    assert_eq!(
        cell_01_left.size,
        Some(24),
        "cell (0,1) left border size should be 24 (from winning border)"
    );
}

/// Verifies SS17.4.66 rule 3: at the shared edge between cell (0,1) and
/// cell (0,2), cell (0,1) has right border double sz=12 green (weight=36)
/// and cell (0,2) has left border single sz=8 black (weight=8). The double
/// green border wins.
#[test]
fn bug4_double_border_beats_single_by_weight() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "adjacent-conflict");
    let table = first_table(&doc);

    // Cell (0,1) right border: double sz=12 green (weight = 3 * 12 = 36)
    let cell_01_right = table.rows[0].cells[1]
        .formatting
        .borders
        .as_ref()
        .and_then(|b| b.right.as_ref())
        .expect("cell (0,1) should have a right border");
    assert_eq!(
        cell_01_right.style,
        BorderStyle::Double,
        "cell (0,1) right should be double"
    );
    assert_eq!(
        cell_01_right.color.as_deref(),
        Some("00FF00"),
        "cell (0,1) right should be green"
    );

    // Cell (0,2) left border: single sz=8 black (weight = 1 * 8 = 8)
    let cell_02_left = table.rows[0].cells[2]
        .formatting
        .borders
        .as_ref()
        .and_then(|b| b.left.as_ref())
        .expect("cell (0,2) should have a left border");

    // Per SS17.4.66 rule 3: green double (weight=36) beats black single (weight=8).
    // After resolution, cell (0,2) left border should show the green double.
    assert_eq!(
        cell_02_left.color.as_deref(),
        Some("00FF00"),
        "cell (0,2) left border should be green (winner from conflict resolution) — \
         SS17.4.66 rule 3: cell (0,1) right double sz=12 (weight=36) beats \
         cell (0,2) left single sz=8 (weight=8)"
    );
    assert_eq!(
        cell_02_left.style,
        BorderStyle::Double,
        "cell (0,2) left border style should be Double (from winning border)"
    );
}

/// Verify that border conflict resolution produces correct post-resolution values.
///
/// Weight formula (MS-OI29500 SS17.4.66(a)):
///   weight = size * style_rank
///   where Single=1, Thick=2, Double=3, dotDash=4, dotDotDash=5, Triple=6, None=0.
///
/// At edge (0,0)|(0,1): sz=24*1=24 > sz=4*1=4 -> cell (0,0) right wins
/// At edge (0,1)|(0,2): sz=12*3=36 > sz=8*1=8 -> cell (0,1) right wins
///
/// After resolution, both sides of each shared edge should agree on the winner.
#[test]
fn bug4_expected_border_weights() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "adjacent-conflict");
    let table = first_table(&doc);

    // Cell (0,0) right: single sz=24 (winner at this edge)
    let r00 = table.rows[0].cells[0]
        .formatting
        .borders
        .as_ref()
        .unwrap()
        .right
        .as_ref()
        .unwrap();
    assert_eq!(r00.style, BorderStyle::Single);
    assert_eq!(r00.size, Some(24));

    // Cell (0,1) left: after resolution, should match cell (0,0) right (sz=24 wins over sz=4)
    let l01 = table.rows[0].cells[1]
        .formatting
        .borders
        .as_ref()
        .unwrap()
        .left
        .as_ref()
        .unwrap();
    assert_eq!(l01.style, BorderStyle::Single);
    assert_eq!(
        l01.size,
        Some(24),
        "after conflict resolution, cell (0,1) left should be sz=24 (winner from cell (0,0) right)"
    );

    // Cell (0,1) right: double sz=12 (winner at this edge)
    let r01 = table.rows[0].cells[1]
        .formatting
        .borders
        .as_ref()
        .unwrap()
        .right
        .as_ref()
        .unwrap();
    assert_eq!(r01.style, BorderStyle::Double);
    assert_eq!(r01.size, Some(12));

    // Cell (0,2) left: after resolution, should match cell (0,1) right (double sz=12 wins over single sz=8)
    let l02 = table.rows[0].cells[2]
        .formatting
        .borders
        .as_ref()
        .unwrap()
        .left
        .as_ref()
        .unwrap();
    assert_eq!(l02.style, BorderStyle::Double);
    assert_eq!(
        l02.size,
        Some(12),
        "after conflict resolution, cell (0,2) left should be double sz=12 (winner from cell (0,1) right)"
    );
}
